{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleLambdaParametersTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

class IndentationRuleLambdaParametersTest {
    private val indentationRuleAssertThat = KtLintAssertThat.assertThatRule { IndentationRule() }

    @Nested
    inner class `Issue 1756 - Lambda parameters on multiple lines` {
        @Test
        fun `Given lambda parameters wrapped across multiple lines with non-ktlint_official code style`() {
            val code =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                  c(a, b)
                }

                class Foo {
                  fun foo() {
                    combine(
                      Any(),
                      Any()
                    ) { a,
                              b ->
                      TODO()
                    }
                  }
                }
                """.trimIndent()
            val formattedCode =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                  c(a, b)
                }

                class Foo {
                  fun foo() {
                    combine(
                      Any(),
                      Any()
                    ) { a,
                            b ->
                      TODO()
                    }
                  }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasLintViolation(11, 1, "Unexpected indentation (14) (should be 12)")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given lambda parameters wrapped across multiple lines with ktlint_official code style`() {
            val code =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                    c(a, b)
                }

                class Foo {
                    fun foo() {
                        combine(
                            Any(),
                            Any()
                        ) { a,
                                  b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            val formattedCode =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                    c(a, b)
                }

                class Foo {
                    fun foo() {
                        combine(
                            Any(),
                            Any()
                        ) { a,
                                b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasLintViolation(11, 1, "Unexpected indentation (18) (should be 16)")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given lambda parameters on single line should remain aligned`() {
            val code =
                """
                class Foo {
                  fun foo() {
                    combine(
                      Any(),
                      Any()
                    ) { a, b ->
                      TODO()
                    }
                  }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given lambda with parameters on new line after brace should use double indent`() {
            val code =
                """
                val fieldExample =
                    LongNameClass {
                        paramA,
                        paramB,
                        paramC ->
                        ClassB(paramA, paramB, paramC)
                    }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given lambda with parameters wrapped with alignment style on first line`() {
            val code =
                """
                val fieldExample =
                    LongNameClass { paramA,
                        paramB,
                        paramC ->
                        ClassB(paramA, paramB, paramC)
                    }
                """.trimIndent()
            val formattedCode =
                """
                val fieldExample =
                    LongNameClass { paramA,
                            paramB,
                            paramC ->
                        ClassB(paramA, paramB, paramC)
                    }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasLintViolations(
                    LintViolation(3, 1, "Unexpected indentation (8) (should be 12)"),
                    LintViolation(4, 1, "Unexpected indentation (8) (should be 12)"),
                ).isFormattedAs(formattedCode)
        }
    }
}
"}

